namespace sv_8f1fd0c330b1496f89aded70566184da.Services;

/// <summary>
/// Provides low-stock alert counts and coordinates polling notifications across
/// all subscribed components within a single circuit.
/// Scoped per circuit — each user gets independent alert state.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int LatestLowStockCount { get; private set; }

    /// <summary>
    /// Fired on the polling thread whenever new alert data arrives.
    /// Subscribers must marshal to the UI thread via InvokeAsync.
    /// </summary>
    public event Func<Task>? OnAlertCountChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += HandleWarehouseChanged;
    }

    /// <summary>Simulates a database query returning a random low-stock count.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Increments the subscriber count and starts polling if this is the first subscriber.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            StartTimer();
        }
    }

    /// <summary>
    /// Decrements the subscriber count and stops polling when no subscribers remain.
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            StopTimer();
        }
    }

    private void StartTimer()
    {
        StopTimer();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopTimer()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire immediately on start so components get data right away.
        await RefreshAsync();

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (_timer is null || !await _timer.WaitForNextTickAsync(ct))
                    break;

                await RefreshAsync();
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task RefreshAsync()
    {
        LatestLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }

    private void HandleWarehouseChanged()
    {
        // When warehouse changes, immediately refresh data if polling is active.
        if (_subscriberCount > 0)
        {
            _ = RefreshAsync();
        }
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= HandleWarehouseChanged;
        StopTimer();
    }
}

